script:
export const meta = {
  name: 'pass7-confirm',
  description: 'Pass-7: two independent agents confirm each of the 6 fixes is appropriate AND complete',
  phases: [{ title: 'Confirm' }],
}

const REPO = '/Users/[REDACTED]/hc-assay'
const DIFF = '/tmp/pass7_code.diff'

const SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['verdict', 'appropriate', 'complete', 'rationale', 'concerns'],
  properties: {
    verdict: { type: 'string', enum: ['CONFIRMED', 'CONCERN', 'REJECTED'] },
    appropriate: { type: 'boolean', description: 'fix addresses the real root cause, no wrong approach' },
    complete: { type: 'boolean', description: 'no remaining gap; regression test actually discriminates' },
    rationale: { type: 'string' },
    concerns: { type: 'array', items: { type: 'string' }, description: 'specific gaps/risks, empty if none' },
  },
}

const FINDINGS = [
  {
    key: 'J-001',
    sev: 'HIGH',
    desc: `Fail-open regression of CV-O-1. The pass-6 fix to scrub ALL text files (not just .jsonl) used strict UTF-8 decode to classify text-vs-binary; a transcript embeds arbitrary subprocess stdout (latin-1, truncated multibyte) inside JSONL strings, so a SINGLE stray non-UTF-8 byte routed the WHOLE file to the verbatim-copy branch, re-leaking PII/secrets. Fix: classify binary by an actual NUL byte (b"\\x00" in raw); otherwise decode errors="replace" so redaction ALWAYS runs. In scripts/capture_transcripts.py _copy_scrubbed. Tests: test_scrub_fails_closed_on_invalid_utf8_bytes, test_copy_scrubbed_scrubs_file_with_invalid_utf8 (and existing test_copy_scrubbed_copies_binary_verbatim must still pass).`,
  },
  {
    key: 'J-002',
    sev: 'HIGH',
    desc: `Operator full display name (e.g. git user.name "[REDACTED]") left in cleartext in committed transcripts — distinct PII the email/username rules don't cover; appears in git author strings, pyproject authors=, prose. Fix: _display_name_patterns() derives names from ASSAY_SCRUB_NAMES env + GIT_AUTHOR_NAME/GIT_COMMITTER_NAME + git config user.name + git log -1 --format=%an; builds a whitespace-flexible regex with NO leading \\b (name often glued to a JSON-escaped \\n) but a trailing \\b (protect "Joneses"), >=4-char guard, de-duped. Applied in _scrub after username redaction. Test: test_scrub_redacts_operator_display_name. ALSO verify the working tree of the repo actually has zero raw occurrences of the operator name in transcripts/ (grep) — a passing unit test does not prove the committed corpus is clean.`,
  },
  {
    key: 'J-003',
    sev: 'MED',
    desc: `CI editable install fetched the hatchling build backend LIVE and un-hashed from PyPI (an unscanned, non-reproducible build-time code-execution window) because builds used default build isolation. Fix: new requirements-build.lock (hashed hatchling/editables/transitive); CI installs it with --require-hashes then "pip install --no-build-isolation --no-deps -e ." in all three lanes (core, integration, license-gate); a reproducibility-guard diff regenerates and compares requirements-build.lock. In .github/workflows/ci.yml + requirements-build.lock. Tests: test_ci_pins_build_backend_and_disables_live_build_isolation.`,
  },
  {
    key: 'J-004',
    sev: 'MED',
    desc: `MLflow TOCTOU: _experiment_id does check-then-create; two concurrent first-time start_run calls (8-thread reasoning pool / multiple study processes on one shared local store) both see None and both create_experiment; MLflow rejects the loser with RESOURCE_ALREADY_EXISTS, the exception propagates out of start_run leaving run_id=None and silently dropping ALL metrics + the provenance artifact. Fix: wrap create_experiment; on any exception re-fetch get_experiment_by_name and return it if now present, else re-raise. In src/assay_engine/observability/tracking.py. Test: test_experiment_id_survives_concurrent_create_race.`,
  },
  {
    key: 'J-005',
    sev: 'MED',
    desc: `Test discrimination gap: RateLimitError and PermanentReasoningError both SUBCLASS ReasoningError, so pytest.raises(ReasoningError) in the "maps to transient" tests does NOT actually discriminate a transient mapping from a rate-limit/permanent one — the test would pass even if T3 misclassified. Fix: _assert_transient(excinfo) asserts the raised exception is NOT an instance of (RateLimitError, PermanentReasoningError); applied to the empty-reply, generic-500, and mid-stream-raise transient tests. In tests/integration/test_reasoning_drain.py.`,
  },
  {
    key: 'J-006',
    sev: 'LOW',
    desc: `License gate ran pip-licenses --format=json --with-system, pulling in system/tooling packages outside the shipped dependency set — can spuriously fail or mask the gate. Fix: drop --with-system so it scans only the installed dependency set (which is the hash-pinned lockfile install). In .github/workflows/ci.yml. Test: test_ci_license_gate_scopes_to_dependency_set.`,
  },
]

function prompt(f, lens) {
  return `You are an independent fix-confirmation reviewer (reviewer ${lens}) for a production-hardening pass on the hc-assay repo at ${REPO}. Be adversarial and skeptical — your job is to find any way the fix is wrong, incomplete, or its regression test fails to discriminate.

FINDING ${f.key} (${f.sev}):
${f.desc}

The complete code diff for all pass-7 fixes is at ${DIFF} (read it). The full files are under ${REPO}. You may run the test suite (cd ${REPO} && source .venv/bin/activate && python -m pytest -q <path>) — NOTE: use "python -m pytest", not bare "pytest", or the tests/ package won't import.

Judge ONLY finding ${f.key}. Decide:
- appropriate: does the fix address the real root cause with a sound approach (not a band-aid, not the wrong layer)?
- complete: is there any remaining gap, AND does the regression test actually FAIL if the fix is reverted (i.e. does it discriminate)? If you can, reason about or test revert-discrimination.
Return CONFIRMED only if both are true. Return CONCERN if appropriate but with a real residual gap. Return REJECTED if the fix is wrong or the test is non-discriminating. List concrete concerns.`
}

phase('Confirm')
const results = await parallel(
  FINDINGS.flatMap((f) => [
    () => agent(prompt(f, 'A'), { label: `confirm:${f.key}:A`, phase: 'Confirm', schema: SCHEMA }).then((v) => ({ key: f.key, sev: f.sev, lens: 'A', v })),
    () => agent(prompt(f, 'B'), { label: `confirm:${f.key}:B`, phase: 'Confirm', schema: SCHEMA }).then((v) => ({ key: f.key, sev: f.sev, lens: 'B', v })),
  ])
)

const clean = results.filter(Boolean)
const byKey = {}
for (const r of clean) {
  byKey[r.key] = byKey[r.key] || { sev: r.sev, votes: [] }
  byKey[r.key].votes.push({ lens: r.lens, ...r.v })
}
const summary = Object.entries(byKey).map(([key, o]) => {
  const bothConfirmed = o.votes.length === 2 && o.votes.every((x) => x.verdict === 'CONFIRMED')
  const anyConcern = o.votes.some((x) => x.verdict === 'CONCERN' || x.verdict === 'REJECTED')
  return { key, sev: o.sev, bothConfirmed, anyConcern, votes: o.votes }
})
log('PASS-7 CONFIRMATION SUMMARY:')
for (const s of summary) {
  log(`${s.key} (${s.sev}): ${s.bothConfirmed ? 'BOTH-CONFIRMED' : 'NEEDS-ATTENTION'} — verdicts ${s.votes.map((v) => v.lens + ':' + v.verdict).join(', ')}`)
}
return { summary }
